// TVMbot Dashboard Module — rendering helpers
// Generated by TIER 1 refactor

/**
 * Dashboard stat helpers
 */
const DashHelper = {
  setText(id, val) {
    const el = document.getElementById(id);
    if (el) el.textContent = val ?? '--';
  },

  setStatusValue(id, val) {
    const el = document.getElementById(id);
    if (!el) return;
    el.textContent = val || '--';
    el.className = 'status-value';
    if (val === 'Connected' || val === 'Online' || val === 'Healthy') el.classList.add('status-ok');
    else if (val === 'Degraded' || val === 'Slow') el.classList.add('status-warn');
    else if (val === 'Disconnected' || val === 'Error' || val === 'Down') el.classList.add('status-error');
  },

  getStatusClass(val) {
    if (!val) return '';
    const v = String(val).toLowerCase();
    if (['connected','online','healthy','ok','done'].includes(v)) return 'status-ok';
    if (['degraded','slow','warning','pending'].includes(v)) return 'status-warn';
    if (['disconnected','error','down','urgent','critical'].includes(v)) return 'status-error';
    return '';
  }
};

